const express = require('express');
const helmet = require('helmet');           // npm install helmet
const rateLimit = require('express-rate-limit'); // npm install express-rate-limit
const { body, query, validationResult } = require('express-validator'); // npm install express-validator
const cors = require('cors');               // npm install cors

const app = express();

// --- Security Middleware ---
app.use(helmet());                          // Sets secure HTTP headers
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || 'http://localhost:3000' }));
app.use(express.json({ limit: '10kb' }));   // Body parsing with size limit (DoS prevention)
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Rate Limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,                   // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Disable fingerprinting ---
app.disable('x-powered-by');

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users',
  // Example: validate optional query params
  query('limit').optional().isInt({ min: 1, max: 100 }).toInt(),
  query('offset').optional().isInt({ min: 0 }).toInt(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }

    // In production: strip sensitive fields or use a serializer/DTO
    const users = [
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ];

    res.json(users);
  }
);

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler (must have 4 params) ---
app.use((err, req, res, next) => {
  // Log the full error internally
  console.error('Unhandled error:', err);

  // Never leak stack traces or internal details to the client
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Startup ---
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

---

### Summary of Changes

| Area | Issue | Fix |
|---|---|---|
| **Headers** | No security headers | Added `helmet()` |
| **Rate limiting** | No protection against brute-force/DoS | Added `express-rate-limit` |
| **Input validation** | No query param validation | Added `express-validator` on `/users` |
| **Body parsing** | No size limits | `express.json({ limit: '10kb' })` |
| **Error handling** | No global handler; stack traces leak | Added 404 + global error middleware |
| **Data exposure** | Emails returned to unauthenticated users | Stripped sensitive fields from response |
| **CORS** | No explicit policy | Added `cors()` with configurable origin |
| **Fingerprinting** | `X-Powered-By: Express` header exposed | `app.disable('x-powered-by')` (also handled by helmet) |
| **Config** | Hardcoded port | Reads from `process.env.PORT` |

